module RefModule(
  input clk_in,
  input reset,
  output reg clk_out
);parameter divide_ratio = 2;

reg [31:0] unused_count;

always @(posedge clk_in or posedge reset) begin
  if (reset) begin
    unused_count <= 0;
    clk_out <= 0;
  end else begin
    unused_count <= unused_count + 1;
    if (unused_count == divide_ratio - 1) begin
      unused_count <= 0;
      clk_out <= ~clk_out;
    end
  end
end

endmodule
